on":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: ბ) მუხ. 14, ნაწ. მე-3."},{"document_test_number":139,"text":"შესაძლებელია თუ არა მსჯავრდებული ადგილსამყოფელის დროებით შეცვლისას გამოცხადდეს და რეგისტრაცია გაიაროს თავისი ფაქტობრივი ადგილსამყოფელის მიხედვით შესაბამის პრობაციის ბიუროში?","options":["ადგილსამყოფელის დროებით, არაუმეტეს 1 თვის ვადით, შეცვლისას მსჯავრდებული შესაძლებელია გამოცხადდეს და რეგისტრაცია გაიაროს თავისი ფაქტობრივი ადგილსამყოფელის მიხედვით შესაბამის პრობაციის ბიუროში;","ადგილსამყოფელის დროებით, არაუმეტეს 3 თვის ვადით, შეცვლისას მსჯავრდებული შესაძლებელია გამოცხადდეს და რეგისტრაცია გაიაროს თავისი ფაქტობრივი ადგილსამყოფელის მიხედვით შესაბამის პრობაციის ბიუროში;","ადგილსამყოფელის დროებით, არაუმეტეს 4 თვის ვადით, შეცვლისას მსჯავრდებული შესაძლებელია გამოცხადდეს და რეგისტრაცია გაიაროს თავისი ფაქტობრივი ადგილსამყოფელის მიხედვით შესაბამის პრობაციის ბიუროში;","ასეთი რამ დაუშვებელია."],"correct_option":"B","correct_option_document_label":"ბ","law_article":"მუხ. 141, ნაწ. მე-8","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: ბ) მუხ. 141, ნაწ. მე-8."},{"document_test_number":140,"text":"მსჯავრდებულის მიერ მსჯავრდებულის საზღვარგარეთ გამგზავრების ნებართვის გარეშე საქართველოს საზღვრის გადაკვეთა ან მისი გადაკვეთის მცდელობა გამოიწვევს თუ არა მსჯავრდებულის დაჯარიმებას?","options":["მსჯავრდებულის მიერ მსჯავრდებულის საზღვარგარეთ გამგზავრების ნებართვის გარეშე საქართველოს საზღვრის გადაკვეთა ან მისი გადაკვეთის მცდელობა გამოიწვევს მსჯავრდებულის დაჯარიმებას პირველ შემთხვევაში - 500 ლარის ოდენობით, პირველი შემთხვევიდან ერთი წლის განმავლობაში განმეორებით ჩადენისას - 1000 ლარის ოდენობით;","გამოიწვევს მსჯავრდებულის დაჯარიმებას პირველ შემთხვევაში - 1000 ლარის ოდენობით, პირველი შემთხვევიდან ერთი წლის განმავლობაში განმეორებით ჩადენისას - 1500 ლარის ოდენობით;","გამოიწვევს მსჯავრდებულის დაჯარიმებას პირველ შემთხვევაში - 1500 ლარის ოდენობით, პირველი შემთხვევიდან ორი წლის განმავლობაში განმეორებით ჩადენისას - 2500 ლარის ოდენობით;","ასეთი დარღვევა მსჯავრდებულის დაჯარიმებას არ გამოიწვევს."],"correct_option":"A","correct_option_document_label":"ა","law_article":"მუხ. 15, ნაწ. მე-6","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: ა) მუხ. 15, ნაწ. მე-6."},{"document_test_number":141,"text":"სასჯელის სახით თანამდებობის დაკავების ან საქმიანობის უფლების ჩამორთმევის აღსრულებისას რა სახის უფლებამოსილებას ახორციელებს პრობაციის ოფიცერი?","options":["პრობაციის ოფიცერს მსჯავრდებული აჰყავს აღრიცხვაზე და აკონტროლებს მისთვის დაკისრებული მოვალეობების შესრულებას;","მსჯავრდებულს განუმარტავს სასჯელის მოხდის წესებს და პირობებს, პერიოდულად აკონტროლებს მისთვის დაკისრებული მოვალეობების შესრულებას;","პრობაციის ოფიცერს მსჯავრდებული აჰყავს აღრიცხვაზე, განუმარტავს მას სასჯელის მოხდის წესებს და პირობებს, პერიოდულად აკონტროლებს მსჯავრდებულისთვის დაკისრებული მოვალეობების შესრულებას;","მსჯავრდებული აჰყავს აღრიცხვაზე და განუმარტავს მას სასჯელის მოხდის წესებს და პირობებს."],"correct_option":"C","correct_option_document_label":"გ","law_article":"მუხ. 25, ნაწ. მე-2","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: გ) მუხ. 25, ნაწ. მე-2."},{"document_test_number":142,"text":"პრობაციის ოფიცრის მოთხოვნის მიღებიდან რა ვადაში უნდა გაათავისუფლოს დამსაქმებელმა თანამდებობის პირმა მსჯავრდებული დაკავებული თანამდებობიდან?","options":["დამსაქმებელმა თანამდებობის პირმა პრობაციის ოფიცრის მოთხოვნის მიღებიდან 3 სამუშაო დღის განმავლობაში უნდა გაათავისუფლოს მსჯავრდებული დაკავებული თანამდებობიდან;","დამსაქმებელმა თანამდებობის პირმა პრობაციის ოფიცრის მოთხოვნის მიღებიდან 5 სამუშაო დღის განმავლობაში უნდა გაათავისუფლოს მსჯავრდებული დაკავებული თანამდებობიდან;","დამსაქმებელმა თანამდებობის პირმა მოთხოვნის მიღებიდან 7 დღის განმავლობაში უნდა გაათავისუფლოს მსჯავრდებული დაკავებული თანამდებობიდან;","ასეთ შემთხვევაში მოთხოვნის მიღებიდან 10 სამუშაო დღის განმავლობაში  მსჯავრდებული უნდა გათავისუფლდეს დაკავებული თანამდებობიდან."],"correct_option":"B","correct_option_document_label":"ბ","law_article":"მუხ. 25, ნაწ. მე-5","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: ბ) მუხ. 25, ნაწ. მე-5."},{"document_test_number":143,"text":"რა ვადაში უნდა აცნობოს დამსაქმებლის ადმინისტრაციამ პრობაციის ბიუროს მსჯავრდებულთან შრომითი ხელშეკრულების შეცვლის ან შეწყვეტის თაობაზე?","options":["აღნიშნულის შესახებ პრობაციის ბიუროს უნდა ეცნობოს დაუყოვნებლივ;","დამსაქმებლის ადმინისტრაციამ პრობაციის ბიუროს აღნიშნულის შესახებ უნდა აცნობოს 3 სამუშაო დღის ვადაში;","დამსაქმებლის ადმინისტრაციამ პრობაციის ბიუროს მსჯავრდებულთან შრომითი ხელშეკრულების შეცვლის ან შეწყვეტის თაობაზე უნდა აცნობოს 5 დღის ვადაში;","პრობაციის ბიუროს მსჯავრდებულთან შრომითი ხელშეკრულების შეცვლის ან შეწყვეტის თაობაზე უნდა ეცნობოს 5 სამუშაო დღის ვადაში."],"correct_option":"D","correct_option_document_label":"დ","law_article":"მუხ. 26, ნაწ. მე-2","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: დ) მუხ. 26, ნაწ. მე-2."},{"document_test_number":144,"text":"რა რეაგირება მოჰყვება იურიდიული პირის მხრიდან შესაბამისი სამართლებრივი აქტის აღსრულებისათვის თავის არიდებას და აკრძალული საქმიანობის გაგრძელებას?","options":["ასეთ შემთხვევაში პრობაციის ოფიცერი მიმართავს პრობაციის ეროვნულ ბიუროს კანონით გათვალისწინებული ღონისძიების გამოყენების თაობაზე;","პრობაციის ბიუროს უფროსი მიმართავს საქართველოს სასჯელაღსრულებისა და პრობაციის მინისტრს საქართველოს კანონმდებლობით გათვალისწინებული ღონისძიების გამოყენების თაობაზე;","იურიდიული პირის მხრიდან შესაბამისი სამართლებრივი აქტის აღსრულებისათვის თავის არიდების და აკრძალული საქმიანობის გაგრძელების შემთხვევაში პრობაციის ბიუროს უფროსი მიმართავს სასამართლოს წარდგინებით საქმიანობის უფლების ჩამორთმევის სასჯელის სხვა სახით შეცვლის შესახებ;","შესაბამისი სამართლებრივი აქტის აღსრულებისათვის თავის არიდების და აკრძალული საქმიანობის გაგრძელების შემთხვევაში პრობაციის ოფიცერი მიმართავს სასამართლოს იურიდიული პირისათვის შეფარდებული საქმიანობის უფლების ჩამორთმევის სასჯელის სხვა სახით შეცვლის შესახებ."],"correct_option":"C","correct_option_document_label":"გ","law_article":"მუხ. 28, ნაწ. მე-4","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: გ) მუხ. 28, ნაწ. მე-4."},{"document_test_number":145,"text":"ვინ განსაზღვრავს მსჯავრდებულისათვის სასჯელის სახით შეფარდებული საზოგადოებისათვის სასარგებლო შრომის სახესა და ყოველდღიურ ხანგრძლივობას?","options":["მსჯავრდებულისათვის სასჯელის სახით შეფარდებული საზოგადოებისათვის სასარგებლო შრომის სახესა და ყოველდღიურ ხანგრძლივობას განსაზღვრავს პრობაციის ბიურო;","მსჯავრდებულისათვის სასჯელის სახით შეფარდებული საზოგადოებისათვის სასარგებლო შრომის სახესა და ყოველდღიურ ხანგრძლივობას განსაზღვრავს სასამართლო;","საზოგადოებისათვის სასარგებლო შრომის სახესა და ყოველდღიურ ხანგრძლივობას განსაზღვრავს პრობაციის ოფიცერი;","სასჯელის სახით შეფარდებული საზოგადოებისათვის სასარგებლო შრომის სახესა და ყოველდღიურ ხანგრძლივობას პრობაციის ბიუროს წარდგინებით განსაზღვრავს საქართველოს სასჯელაღსრულებისა და პრობაციის მინისტრი."],"correct_option":"A","correct_option_document_label":"ა","law_article":"მუხ. 29, ნაწ. 1","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: ა) მუხ. 29, ნაწ. 1."},{"document_test_number":146,"text":"შესაძლებელია თუ არა, მსჯავრდებულმა საზოგადოებისათვის სასარგებლოდ იმუშაოს დასვენების დღეებში?","options":["მსჯავრდებულს, პრობაციის ბიუროს თანხმობის შემთხვევაში, უფლება აქვს საზოგადოებისათვის სასარგებლოდ იმუშაოს დასვენების დღეებში;","აქვს უფლება, საზოგადოებისათვის სასარგებლოდ იმუშაოს დასვენების დღეებში, თუ აღნიშნულზე არსებობს საქართველოს სასჯელაღსრულებისა და პრობაციის მინისტრის წერილობითი თანხმობა;","მსჯავრდებულს, თავისი სურვილით, სათანადო პირობების არსებობის შემთხვევაში, უფლება აქვს საზოგადოებისათვის სასარგებლოდ იმუშაოს დასვენების დღეებში;","მსჯავრდებულს არც ერთ შემთხვევაში არა აქვს უფლება საზოგადოებისათვის სასარგებლოდ იმუშაოს დასვენების დღეებში."],"correct_option":"C","correct_option_document_label":"გ","law_article":"მუხ. 30, ნაწ. მე-2","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: გ) მუხ. 30, ნაწ. მე-2."},{"document_test_number":147,"text":"რა შედეგი მოჰყვება მსჯავრდებულისათვის საზოგადოებისათვის სასარგებლო შრომაზე უარს ან მასზე ჯიუტად თავის არიდებას?","options":["თუ მსჯავრდებული უარს აცხადებს საზოგადოებისათვის სასარგებლო შრომაზე ან  ჯიუტად თავის არიდებას მას, პრობაციის ოფიცერი მიმართავს სასამართლოს წარდგინებით საზოგადოებისათვის სასარგებლო შრომის სასჯელის სხვა სახით შეცვლის შესახებ;","თუ მსჯავრდებული უარს აცხადებს საზოგადოებისათვის სასარგებლო შრომაზე ან  ჯიუტად თავის არიდებას მას, პრობაციის ბიუროს უფროსი მიმართავს სასამართლოს წარდგინებით საზოგადოებისათვის სასარგებლო შრომის სასჯელის სხვა სახით შეცვლის შესახებ;","ასეთ შემთხვევაში პრობაციის ბიურო კანონით გათვალისწინებული ღონისძიების გამოყენების შუამდგომლობით მიმართავს საქართველოს სასჯელაღსრულებისა და პრობაციის მინისტრს;","ასეთ შემთხვევაში პრობაციის ბიუროს შუამდგომლობით საქართველოს სასჯელაღსრულებისა და პრობაციის მინისტრი მიმართავს სასამართლოს წარდგინებით საზოგადოებისათვის სასარგებლო შრომის სასჯელის სხვა სახით შეცვლის შესახებ."],"correct_option":"B","correct_option_document_label":"ბ","law_article":"მუხ. 33, ნაწ. მე-2","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: ბ) მუხ. 33, ნაწ. მე-2."},{"document_test_number":148,"text":"შესაძლებელია თუ არა მსჯავრდებული კონკრეტულ დღეს გათავისუფლდეს  სამუშაოს შესრულებისგან?","options":["მსჯავრდებულის კონკრეტულ დღეს სამუშაოს შესრულებისგან გათავისუფლება  დაუშვებელია;","დამსაქმებელს, პრობაციის ბიუროს უფროსთან შეთანხმებით, შეუძლია მსჯავრდებული კონკრეტულ დღეს გაათავისუფლოს სამუშაოს შესრულებისგან;","დამსაქმებელს, პრობაციის ოფიცერთან შეთანხმებით, შეუძლია მსჯავრდებული კონკრეტულ დღეს გაათავისუფლოს სამუშაოს შესრულებისგან;","პატივსადები მიზეზების არსებობისას დამსაქმებელს, პრობაციის ოფიცერთან შეთანხმებით, შეუძლია მსჯავრდებული კონკრეტულ დღეს გაათავისუფლოს სამუშაოს შესრულებისგან."],"correct_option":"D","correct_option_document_label":"დ","law_article":"მუხ. 33, ნაწ. მე-4","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: დ) მუხ. 33, ნაწ. მე-4."},{"document_test_number":149,"text":"ეკრძალება თუ არა მსჯავრდებულს სამუშაოდან გათავისუფლება გამასწორებელი სამუშაოს მოხდის პერიოდში?","options":["გამასწორებელი სამუშაოს მოხდის პერიოდში მსჯავრდებულს ეკრძალება სამუშაოდან გათავისუფლება პრობაციის ოფიცრის წერილობითი ნებართვის გარეშე;","გამასწორებელი სამუშაოს მოხდის პერიოდში მსჯავრდებულს ეკრძალება სამუშაოდან გათავისუფლება;","გამასწორებელი სამუშაოს მოხდის პერიოდში მსჯავრდებულს ეკრძალება სამუშაოდან გათავისუფლება პრობაციის ბიუროს წერილობითი ნებართვის გარეშე;","გამასწორებელი სამუშაოს მოხდის პერიოდში მსჯავრდებულს ეკრძალება სამუშაოდან გათავისუფლება პრობაციის ბიუროს ნებართვის გარეშე."],"correct_option":"C","correct_option_document_label":"გ","law_article":"მუხ. 35, ნაწ. 1","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: გ) მუხ. 35, ნაწ. 1."},{"document_test_number":150,"text":"რა ვადაში ეცნობება მსჯავრდებულს საცხოვრებელი ადგილის შეცვლის ნებართვის გაცემის შესახებ პრობაციის ბიუროს უფროსის გადაწყვეტილება?","options":["საცხოვრებელი ადგილის შეცვლის ნებართვის გაცემის შესახებ პრობაციის ბიუროს უფროსის გადაწყვეტილება მსჯავრდებულს ეცნობება წერილობით, განცხადების მიღებიდან არა უგვიანეს 2 კვირისა;","საცხოვრებელი ადგილის შეცვლის ნებართვის გაცემის შესახებ პრობაციის ბიუროს უფროსის გადაწყვეტილება მსჯავრდებულს ეცნობება წერილობით, განცხადების მიღებიდან არა უგვიანეს 1 კვირისა;","გადაწყვეტილება მსჯავრდებულს ეცნობება განცხადების მიღებიდან არა უგვიანეს 10 დღისა;","გადაწყვეტილება მსჯავრდებულს ეცნობება წერილობით, განცხადების მიღებიდან არა უგვიანეს 5 სამუშაო დღისა."],"correct_option":"A","correct_option_document_label":"ა","law_article":"მუხ. 41, ნაწ. მე-2","explanation":"სწორი პასუხი დოკუმენტის პასუხების სიის მიხედვით: ა) მუხ. 41, ნაწ. მე-2."}]$questions$::jsonb)
  loop
    select id into v_question_id
    from public.questions
    where law_id = v_law_id and text = r.question->>'text';

    if v_question_id is null then
      insert into public.questions (
        category_id, subcategory_id, law_id, text, difficulty, explanation,
        law_name, law_article, source_url, law_version_date,
        needs_review, is_prime, is_published, verified_at
      ) values (
        v_category_id, v_subcategory_id, v_law_id,
        r.question->>'text', 'medium', r.question->>'explanation',
        'სასჯელაღსრულების სამართალი', r.question->>'law_article', '', current_date,
        false, false, true, now()
      ) returning id into v_question_id;

      insert into public.question_options (question_id, option_text, is_correct, sort_order)
      select
        v_question_id,
        option.value,
        case option.ordinality
          when 1 then r.question->>'correct_option' = 'A'
          when 2 then r.question->>'correct_option' = 'B'
          when 3 then r.question->>'correct_option' = 'C'
          when 4 then r.question->>'correct_option' = 'D'
        end,
        option.ordinality
      from jsonb_array_elements_text(r.question->'options') with ordinality as option(value, ordinality);
    end if;
  end loop;
end $$;
